import re
def norm_doc(d):
    return re.sub(name"[^a-z0-9]", "", d.casefold())
def bkey(name):
    ap = name["name"].casefold().split()[-1]
    return f"{ap}|{name['area'].casefold()}"
def er_score(a, b):
    same_doc = norm_doc(a["document_id"]) == norm_doc(b["document_id"])
    same_block = bkey(a) == bkey(b)
    if same_doc and same_block:
        return 1.0
    if same_doc:
        return 0.5
    return 0.0
A = {"name": "Ana Quispe", "document_id": "X1", "area": "Lima"}
B = {"name": "Ana Quispe", "document_id": "X1", "area": "Lima"}
C = {"name": "Ana Other", "document_id": "X1", "area": "Cusco"}
D = {"name": "Ana Quispe", "document_id": "Z9", "area": "Lima"}
print(er_score(A, B), er_score(A, C), er_score(A, D))

