# agentic_I2 skeptic-crosscheck · S13-T2-B-E2
ops = [("A","D",1), ("C","D",1), ("A","E",1), ("C","F",1)]
def neighbors(ops, node):
    s = set()
    for x, y, _ in ops:
        if x == node:
            s.add(y)
        if y == node:
            s.add(x)
    return s
def common_counterparties(ops, a, c):
    return sorted(neighbors(ops, a) & neighbors(ops, c))
print(common_counterparties(ops, "A", "C"))

# agentic_I2 skeptic-crosscheck · S13-T3-B-E2
from math import isfinite

th = {"accept_min": 0.8, "review_low": 0.4}
def decide_ops_status(score, unc, th):
    if isinstance(score, bool) or not isinstance(score, (int, float)):
        return "invalid_input"
    if not isfinite(score) or not 0.0 <= score <= 1.0 or unc not in {"low", "med", "high"}:
        return "invalid_input"
    if unc == "high":
        return "needs_review"
    if score < th["review_low"]:
        return "abstain"
    if score < th["accept_min"]:
        return "needs_review"
    return "accept_pair"
for s, u in [(-0.1, "low"), (0.399, "low"), (0.4, "low"), (0.799, "med"), (0.8, "low"), (0.9, "high"), (float("nan"), "low")]:
    print(s, u, decide_ops_status(s, u, th))

